mapper.select:
select id, name, phone, room_type as roomType, room_number as roomNumber, checkin, checkout, nights, amount, status, case status when 'confirmed' then '已确认' when 'cancelled' then '已取消' when 'checked_in' then '已入住' when 'checked_out' then '已退房' else '未知' end as statusName, remark from reservation
and status = #{status}
order by id
